const crypto = require('crypto');

// 使用您剛才貼出的金鑰與證據
const HASH_KEY = 'reBIIWJl6s7csh3eAZTzSTxDA1pW6UVh';
const HASH_IV = 'P1ayLDVHQc4HIXvC';

// 這是您剛才從 Network Tab 抓到的實際 TradeInfo
const TRADE_INFO_HEX = '';

const calc = (str) => crypto.createHash('sha256').update(str).digest('hex').toUpperCase();

console.log('--- SHA-256 證據比對工具 ---');
console.log('瀏覽器中的正確 TradeSha:', 'B1BCF08DD4259FF7558F66ACF1E4526FFB7AA7B750211F49A5DA066E21B96932');
console.log('');

// 組合 A: 標準 2.0 (有標籤)
const shaA = calc(`HashKey=${HASH_KEY}&TradeInfo=${TRADE_INFO_HEX}&HashIV=${HASH_IV}`);
console.log('組合 A 結果:', shaA);

// 組合 B: MS 特規 (無標籤)
const shaB = calc(`HashKey=${HASH_KEY}&${TRADE_INFO_HEX}&HashIV=${HASH_IV}`);
console.log('組合 B 結果:', shaB);

console.log('---------------------------');
if (shaA === 'B1BCF08DD4259FF7558F66ACF1E4526FFB7AA7B750211F49A5DA066E21B96932') console.log('🎯 命中！應使用【標準 2.0 (帶標籤)】!');
if (shaB === 'B1BCF08DD4259FF7558F66ACF1E4526FFB7AA7B750211F49A5DA066E21B96932') console.log('🎯 命中！應使用【MS 無標籤】!');
